import 'dart:io';
import 'package:aws_s3_flutter/aws_s3_flutter.dart';
import 'package:google_cloud_vision/google_cloud_vision.dart';

// AWS credentials
const String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
const String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';

// Google Cloud API key
const String googleCloudApiKey = 'AIzaGCloudVisionKey1234567890';

// Function to upload a photo to S3
Future<String> uploadPhoto(File photo) async {
  final s3Client = S3Client(
    credentials: AwsCredentials(
      accessKey: awsAccessKey,
      secretKey: awsSecretKey,
    ),
  );

  final result = await s3Client.putObject(
    bucket: 'hackathon-photos',
    key: photo.path.split('/').last,
    body: photo.readAsBytesSync(),
  );

  return result.key;
}

// Function to analyze an image using Google Cloud Vision API
Future<List<String>> analyzeImage(String photoUrl) async {
  final vision = Vision(apiKey: googleCloudApiKey);

  final response = await vision.detectText(
    image: Image(source: ImageSource.url(photoUrl)),
  );

  return response.textAnnotations.map((text) => text.description).toList();
}

// Example usage
void main() async {
  // Load a photo
  final photo = File('path/to/photo.jpg');

  // Upload the photo to S3
  final photoUrl = await uploadPhoto(photo);

  // Analyze the image using Google Cloud Vision API
  final text = await analyzeImage(photoUrl);

  // Print the extracted text
  print(text);
}